SELECT quantity_in_stock
FROM inventory
WHERE item_id = 0;

SELECT c.customer_name
FROM customers c
WHERE c.customer_id IN (
    SELECT s.customer_id
    FROM sales s
    WHERE s.total_price > (
        SELECT AVG(total_price)
        FROM sales
    )
);

SELECT DISTINCT customers.customer_name
FROM customers
JOIN returns ON customers.customer_id = returns.customer_id;

SELECT item_id, category_id
FROM clothing_items
WHERE item_name = 'Casual Top';
